    new Setting(containerEl)
      .setName("Model")
      .setDesc("Optional. Passed as `--model` to the CLI. Leave blank to use Claude Code's default.")
      .addText((t) =>
        t
          .setPlaceholder("e.g. claude-opus-4-7")
